1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_PERCENT = 110;
3	
4	type Item = { type: string; cursed?: boolean; enchantment?: number };
5	type Customer = { yearsWithMHPCO: number };
6	type Scenario = { customer: Customer; steps: { items: Item[] }[] };
7	
8	type ItemKind = {
9	  basePremium: number;
10	  isComponent: boolean;
11	};
12	
13	const ITEM_CATALOG: Record<string, ItemKind> = {
14	  sword: { basePremium: 100, isComponent: false },
15	  amulet: { basePremium: 60, isComponent: false },
16	  staff: { basePremium: 80, isComponent: false },
17	  potion: { basePremium: 40, isComponent: false },
18	  rune: { basePremium: 25, isComponent: true },
19	  moonstone: { basePremium: 25, isComponent: true },
20	};
21	
22	const BLOCK_PRICE = 60;
23	const BLOCK_SIZE = 3;
24	
25	const countByType = (items: Item[]): Record<string, number> =>
26	  items.reduce<Record<string, number>>((counts, item) => {
27	    counts[item.type] = (counts[item.type] ?? 0) + 1;
28	    return counts;
29	  }, {});
30	
31	const premiumForTypeGroup = (type: string, count: number): number => {
32	  const kind = ITEM_CATALOG[type];
33	  const formsBlock = kind.isComponent && count === BLOCK_SIZE;
34	  return formsBlock ? BLOCK_PRICE : kind.basePremium * count;
35	};
36	
37	const policyBaseFor = (items: Item[]): number =>
38	  Object.entries(countByType(items)).reduce(
39	    (total, [type, count]) => total + premiumForTypeGroup(type, count),
40	    0,
41	  );
42	
43	const CURSE_SURCHARGE_RATE = 0.5;
44	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
45	const HIGH_ENCHANTMENT_THRESHOLD = 5;
46	
47	const isCursed = (item: Item): boolean => item.cursed === true;
48	const isHighlyEnchanted = (item: Item): boolean =>
49	  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD;
50	
51	const itemSurchargeFor = (item: Item): number => {
52	  const basePremium = ITEM_CATALOG[item.type].basePremium;
53	  const curseSurcharge = isCursed(item) ? basePremium * CURSE_SURCHARGE_RATE : 0;
54	  const highEnchantmentSurcharge = isHighlyEnchanted(item)
55	    ? basePremium * HIGH_ENCHANTMENT_SURCHARGE_RATE
56	    : 0;
57	  return curseSurcharge + highEnchantmentSurcharge;
58	};
59	
60	const perItemSurchargesFor = (items: Item[]): number =>
61	  items.reduce((total, item) => total + itemSurchargeFor(item), 0);
62	
63	const LOYALTY_THRESHOLD_YEARS = 2;
64	const LOYALTY_DISCOUNT_PERCENT = 20;
65	
66	const applyPolicyModifiers = (policyBase: number, customer: Customer): number => {
67	  const firstInsuranceSurcharge = Math.ceil(
68	    (policyBase * (FIRST_INSURANCE_PERCENT - 100)) / 100,
69	  );
70	  const loyaltyDiscount =
71	    customer.yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS
72	      ? Math.ceil((policyBase * LOYALTY_DISCOUNT_PERCENT) / 100)
73	      : 0;
74	  return policyBase + firstInsuranceSurcharge - loyaltyDiscount;
75	};
76	
77	const quoteFor = (items: Item[], customer: Customer): number =>
78	  applyPolicyModifiers(policyBaseFor(items), customer) +
79	  perItemSurchargesFor(items) +
80	  PROCESSING_FEE;
81	
82	export const runScenario = (input: unknown): unknown => {
83	  const scenario = input as Scenario;
84	  const items = scenario.steps[0].items;
85	  return { results: [{ premium: quoteFor(items, scenario.customer) }] };
86	};
