const LOYALTY_THRESHOLD_YEARS = 2;
const LOYALTY_DISCOUNT_PERCENT = 20;

const percentOf = (amount: number, percent: number): number =>
  Math.ceil((amount * percent) / 100);

const isLoyalCustomer = (customer: Customer): boolean =>
  customer.yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS;

const applyPolicyModifiers = (policyBase: number, customer: Customer): number => {
  const firstInsuranceSurcharge = percentOf(policyBase, FIRST_INSURANCE_SURCHARGE_PERCENT);
  const loyaltyDiscount = isLoyalCustomer(customer)
    ? percentOf(policyBase, LOYALTY_DISCOUNT_PERCENT)
    : 0;
  return policyBase + firstInsuranceSurcharge - loyaltyDiscount;
};

